from itertools import permutations

n, k = map(int, input().split())

p = list(permutations(range(1, n + 1)))

count = 0
for i in p:
    oddness = 0
    for j in range(n):
        oddness += abs(j - i[j])
    if oddness == k:
        count += 1

print(count % (10**9 + 7))



