from math import factorial

n, k = map(int, input().split())

def c(n, k):
    return factorial(n) // (factorial(k) * factorial(n - k))

def f(n, k):
    if k > n * (n + 1) // 2:
        return 0
    if k == n * (n + 1) // 2:
        return 1
    if k == 0:
        return 1
    if k < 0:
        return 0
    return f(n - 1, k) + f(n - 1, k - n)

print(f(n, k) % (10**9 + 7))
